module RefModule (
    input wire clk,
    input wire reset,
    input wire serial_in,
    input wire load,
    output reg [4:0] parallel_out
);
    reg [4:0] shift_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset) begin
            shift_reg <= 5'b00000;
            parallel_out <= 5'b00000;
        end else if (load) begin
            parallel_out <= shift_reg;
        end else begin
            shift_reg <= {shift_reg[3:0], serial_in}; // Shift left and insert serial input
        end
    end
endmodule
